                    </div>
                    <div className="flex gap-2">
                        <dt className="text-muted-foreground min-w-24">
                            Actualizado:
                        </dt>
                        <dd>
                            {new Intl.DateTimeFormat("es-ES", {
                                dateStyle: "long",
                                timeStyle: "short",
                            }).format(new Date(category.updatedAt))}
                        </dd>
                    </div>
                </dl>
            </div>
        </div>
    );
}

/**
 * @fileoverview Formulario reutilizable para crear/editar categorías.
 * @module features/categories/components/category-form
 */

"use client";

import { useRouter } from "next/navigation";
import { useForm, type Resolver } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import {
    categorySchema,
    type CategoryFormData,
} from "../validations";
import {
    Button,
    Input,
    Label,
    SingleFormError,
} from "@/features/shared/components/ui";
import { cn } from "@/lib/utils";

interface CategoryFormProps {
    defaultValues?: Partial<CategoryFormData>;
    onSubmit: (data: CategoryFormData) => void;
    isPending?: boolean;
    submitLabel?: string;
    cancelLabel?: string;
    cancelHref?: string;
    className?: string;
}

export function CategoryForm({
    defaultValues,
    onSubmit,
    isPending,
    submitLabel = "Guardar",
    cancelLabel = "Cancelar",
    cancelHref,
    className,
}: CategoryFormProps) {
    const router = useRouter();

    const {
        register,
        handleSubmit,
        formState: { errors },
    } = useForm<CategoryFormData>({
        resolver: zodResolver(categorySchema as any) as unknown as Resolver<CategoryFormData>,
        defaultValues: {
            name: "",
            description: null,
            isActive: true,
            ...defaultValues,
        },
        mode: "onBlur",
    });

    return (
        <form
            onSubmit={handleSubmit(onSubmit)}
            className={cn("space-y-6", className)}
        >
            <div className="space-y-2">
                <Label htmlFor="name">Nombre</Label>
                <Input
                    id="name"
                    placeholder="Nombre de la categoría"
                    {...register("name")}
