// ============================================================================
// @fileoverview Esquema Prisma para la base de datos PostgreSQL.
//   Define los modelos Category y Product con relación 1:N.
//
// @description
// - Modelos mapeados a tablas: categories, products
// - IDs UUID v4 autogenerados
// - Timestamps createdAt/updatedAt automáticos
// - Índices en campos de búsqueda frecuente
// - Relación Category → Product con onDelete: Restrict
// ============================================================================

generator client {
  provider = "prisma-client"
  output   = "../lib/generated/prisma"
}

datasource db {
  provider = "postgresql"
}

// ---------------------------------------------------------------------------
// Modelo Category
// - isActive: controla visibilidad (default: true)
// - name: único (combinado con @@unique)
// - slug: único para URLs amigables
// - products: relación 1:N con Product
// ---------------------------------------------------------------------------
model Category {
  id          String    @id @default(uuid()) @map("id")
  name        String    @map("name")
  slug        String    @unique @map("slug")
  description String?   @map("description")
  isActive    Boolean   @default(true) @map("is_active")
  createdAt   DateTime  @default(now()) @map("created_at")
  updatedAt   DateTime  @updatedAt @map("updated_at")

  products    Product[]

  @@unique([name])
  @@map("categories")
}

// ---------------------------------------------------------------------------
// Modelo Product
// - categoryId: FK a Category (onDelete: Restrict — no se puede eliminar
//   una categoría que tenga productos asociados)
// - price: Decimal(10,2) para precisión monetaria
// - Índices en: categoryId, name, slug, price (optimiza búsquedas)
// - Unique compuesto: [categoryId, name] (un nombre único por categoría)
// ---------------------------------------------------------------------------
model Product {
  id          String    @id @default(uuid()) @map("id")
  categoryId  String    @map("category_id")
  name        String    @map("name")
  slug        String    @unique @map("slug")
  description String?   @map("description")
  price       Decimal   @map("price") @db.Decimal(10, 2)
  createdAt   DateTime  @default(now()) @map("created_at")
  updatedAt   DateTime  @updatedAt @map("updated_at")

  category    Category  @relation(fields: [categoryId], references: [id], onDelete: Restrict, onUpdate: Cascade)

  @@index([categoryId])
  @@index([name])
  @@index([slug])
  @@index([price])
  @@unique([categoryId, name])

  @@map("products")
}

